const searchValue = e.args[0] || "";

if (window._serialNoDropdownDebounceTimer) {
    clearTimeout(window._serialNoDropdownDebounceTimer);
}

if (window._serialNoDropdownAbortController) {
    window._serialNoDropdownAbortController.abort();
}

window._serialNoDropdownAbortController = new AbortController();
const signal = window._serialNoDropdownAbortController.signal;

window._serialNoDropdownDebounceTimer = setTimeout(async () => {
    let savedToken = localStorage.getItem('dlms_auth_token') || localStorage.getItem('nowpurchase_token');

    if (!savedToken) {
        return;
    }

    const assemblyData = window._selectedAssemblyData;
    if (!assemblyData) {
        if (e.setUserDefinedProps) {
            e.setUserDefinedProps({ data: [] });
        }
        return;
    }

    const allowedCastingNames = [];
    for (let i = 1; i <= 10; i++) {
        const castingName = assemblyData[`part_${i}_name`];
        if (castingName && !allowedCastingNames.includes(castingName)) {
            allowedCastingNames.push(castingName);
        }
    }

    let requestBody = {
        "fields": [
            "data.main.data.parent_data__serial_no",
            "data.main.data.parent_data__casting_name",
            "data.main.data.parent_data__casting_id"
        ],
        "search_fields": ["data.main.data.parent_data__casting_name", "data.main.data.parent_data__serial_no"],
        "search": searchValue || "",
        "status": "pending",
        "limit": 100
    };

    try {
        const res = await fetch('https://dlms-api.iotnp.com/api/v1/templates/assembly_operational/dropdown/v2', {
            method: 'POST',
            headers: {
                'accept': 'application/json',
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${savedToken}`
            },
            body: JSON.stringify(requestBody),
            signal: signal
        });

        if (!res.ok) {
            return;
        }

        const response = await res.json();
        const items = Array.isArray(response.data) ? response.data : [];

        if (!window._serialNoDataLookup) {
            window._serialNoDataLookup = new Map();
        }

        const filteredItems = items.filter(item => {
            const castingName = item["data.main.data.parent_data__casting_name"] || "";
            return allowedCastingNames.length === 0 || allowedCastingNames.includes(castingName);
        });

        const preparedData = filteredItems.map(item => {
            const serialNo = item["data.main.data.parent_data__serial_no"] || "";
            const castingName = item["data.main.data.parent_data__casting_name"] || "";
            const castingId = item["data.main.data.parent_data__casting_id"] || "";

            window._serialNoDataLookup.set(serialNo, {
                _id: item._id,
                serial_no: serialNo,
                casting_name: castingName,
                casting_id: castingId
            });

            return {
                value: serialNo,
                label: `${serialNo} - ${castingName}`,
                data: {
                    _id: item._id,
                    serial_no: serialNo,
                    casting_name: castingName,
                    casting_id: castingId
                }
            };
        });

        if (e.setUserDefinedProps) {
            e.setUserDefinedProps({ data: preparedData });
        }

    } catch (err) {
        if (err.name === 'AbortError') {
            return;
        }
        console.error("Fetch error:", err);
    }

}, 300);

on_change_serial_number.body:
 const selectedValues = e.args[0] || [];
const assemblyData = window._selectedAssemblyData || {};

// Build casting NAME to info mapping from assembly data
const castingNameToInfo = new Map();
for (let i = 1; i <= 10; i++) {
    const partId = assemblyData[`part_${i}_id`];
    const partLimit = parseInt(assemblyData[`part_${i}_limit`]) || 0;
    const partName = assemblyData[`part_${i}_name`] || "";
    if (partId && partName) {
        if (castingNameToInfo.has(partName)) {
            // If name already exists, merge: accumulate limit, collect all IDs
            const existing = castingNameToInfo.get(partName);
            existing.castingIds.push(partId);
            existing.limit += partLimit;
        } else {
            castingNameToInfo.set(partName, {
                name: partName,
                castingIds: [partId],
                bogieId: e.data?.bogie_id,
                limit: partLimit,
                serialNos: [],
                count: 0
            });
        }
    }
}

// Group selected serial numbers by casting NAME
const documentIds = [];

if (window._serialNoDataLookup && selectedValues.length > 0) {
    selectedValues.forEach(serialNo => {
        const data = window._serialNoDataLookup.get(serialNo);
        if (data) {
            const castingName = data.casting_name;
            if (castingNameToInfo.has(castingName)) {
                castingNameToInfo.get(castingName).serialNos.push(serialNo);
                castingNameToInfo.get(castingName).count++;
            }
            if (data._id) {
                documentIds.push(data._id);
            }
        }
    });
}

const castings = {};
const validationErrors = [];
let groupIndex = 0;

castingNameToInfo.forEach((info, castingName) => {
    if (groupIndex < 10) {
        e.data[`casting_group__${groupIndex}__name`] = info.name;
        e.data[`casting_group__${groupIndex}__serial_nos`] = info.serialNos.join(", ");
        e.data[`casting_group__${groupIndex}__count`] = info.count;
        e.data[`casting_group__${groupIndex}__id`] = info.castingIds.join(", ");
        e.data[`casting_group__${groupIndex}__limit`] = info.limit;
        e.data[`casting_group__${groupIndex}__bogieID`] = e.data?.bogie_id;

        castings[info.name] = {
            ids: info.castingIds,
            bogieID: e.data.bogie_id,
            serialNumbers: info.serialNos,
            count: info.count,
            limit: info.limit
        };

        if (info.limit > 0 && info.count !== info.limit) {
            validationErrors.push(`${info.name}: Selected ${info.count}, required ${info.limit}`);
        }

        groupIndex++;
    }
});

// Clear remaining groups
for (let i = groupIndex; i < 10; i++) {
    e.data[`casting_group__${i}__name`] = "";
    e.data[`casting_group__${i}__serial_nos`] = "";
    e.data[`casting_group__${i}__count`] = 0;
    e.data[`casting_group__${i}__id`] = "";
    e.data[`casting_group__${i}__limit`] = 0;
    e.data[`casting_group__${i}__bogieID`] = null;
}

e.data.castings = castings;
e.data.meta__unique_casting_count = castingNameToInfo.size;
e.data.meta__total_selected_count = selectedValues.length;
e.data.selected_document_ids = documentIds;
e.data.selection_validation_errors = validationErrors;

